  if (t.startsWith('```')) {
    const nl = t.indexOf('\n');
    t = nl === -1 ? '' : t.slice(nl + 1);
  }
  const end = t.lastIndexOf('```');
  if (end !== -1) t = t.slice(0, end).trim();
  return t.trim();
}
